<?php
 namespace League\CommonMark\Extension\SmartPunct; use League\CommonMark\ElementRendererInterface; use League\CommonMark\HtmlElement; use League\CommonMark\Inline\Element\AbstractInline; use League\CommonMark\Inline\Renderer\InlineRendererInterface; final class QuoteRenderer implements InlineRendererInterface { public function render(AbstractInline $inline, ElementRendererInterface $htmlRenderer) { if (!$inline instanceof Quote) { throw new \InvalidArgumentException(sprintf('Expected an instance of "%s", got "%s" instead', Quote::class, get_class($inline))); } if ($inline->getContent() === Quote::SINGLE_QUOTE) { return Quote::SINGLE_QUOTE_CLOSER; } elseif ($inline->getContent() === Quote::DOUBLE_QUOTE) { return Quote::DOUBLE_QUOTE_OPENER; } return $inline->getContent(); } } 